const msg = $json.body?.message || {};
const call = msg.call || {};
const vars = call.assistantOverrides?.variableValues || {};
const analysis = msg.analysis || {};
const structured = analysis.structuredData || {};
const artifact = msg.artifact || {};
const recordingUrl = artifact.recordingUrl || msg.recordingUrl || '';

// Extract outcome: try structuredData first, then infer from endedReason
let outcome = structured.outcome || '';
if (!outcome) {
  const reason = msg.endedReason || '';
  const dur = msg.durationSeconds || 0;
  if (reason.includes('voicemail') || reason.includes('machine')) outcome = 'voicemail';
  else if (reason.includes('no-answer') || dur < 10) outcome = 'no_answer';
  else outcome = 'completed';
}

// Check if customer asked to be removed
const transcript = (msg.transcript || '').toLowerCase();
const removed = transcript.includes('remove me') || transcript.includes('do not call') || outcome === 'removed_from_list';
if (removed) outcome = 'removed_from_list';

return [{ json: {
  call_id: call.id || '',
  phone: (call.customer?.number || '').replace(/\D/g,'').replace(/^1/,''),
  business_name: call.customer?.name || vars.business_name || '',
  industry: vars.industry || '',
  city: vars.city || '',
  rating: vars.rating || '',
  reviews_count: vars.reviews_count || '',
  duration_seconds: msg.durationSeconds || 0,
  ended_reason: msg.endedReason || '',
  outcome: outcome,
  removed_from_list: removed,
  summary: analysis.summary || msg.summary || '',
  notes: structured.notes || '',
  recording_url: recordingUrl,
  transcript: (msg.transcript || '').substring(0, 2000),
  timestamp: new Date().toISOString()
} }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.callResults) staticData.callResults = [];
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  if (staticData.callResults.length >= 500) staticData.callResults = staticData.callResults.slice(-400);
  staticData.callResults.push({
    call_id: j.call_id || '',
    phone: j.phone || '',
    business_name: j.business_name || '',
    outcome: j.outcome || '',
    duration_seconds: j.duration_seconds || 0,
    summary: (j.summary || '').substring(0, 500),
    transcript: (j.transcript || '').substring(0, 2000),
    removed_from_list: j.removed_from_list === true,
    timestamp: new Date().toISOString()
  });
  out.push({ json: j });
}
return out;

const src = $('Save Result (Internal)').all();
const out = [];
for (const item of src) {
  const j = item.json;
  let head;
  if (j.outcome === 'meeting_booked') head = 'MEETING GEBUCHT!!!';
  else if (j.outcome === 'callback_requested') head = 'Callback gewuenscht';
  else if (j.outcome === 'voicemail') head = 'Voicemail hinterlassen';
  else if (j.outcome === 'no_answer') head = 'Nicht erreicht';
  else if (j.outcome === 'not_interested') head = 'Kein Interesse';
  else if (j.outcome === 'wrong_number') head = 'Falsche Nummer';
  else if (j.outcome === 'removed_from_list') head = 'Von Liste entfernt (nie wieder anrufen)';
  else head = 'Anruf beendet: ' + (j.outcome || '?');

  const mins = Math.floor((j.duration_seconds || 0) / 60);
  const secs = (j.duration_seconds || 0) % 60;
  let text = 'ANRUF-ERGEBNIS: ' + head + '\n\n';
  text += 'Firma: ' + (j.business_name || '?') + '\n';
  text += 'Telefon: ' + (j.phone || '') + '\n';
  text += 'Branche: ' + (j.industry || '?') + ' (' + (j.city || '?') + ')\n';
  text += 'Dauer: ' + (mins > 0 ? mins + 'm ' : '') + secs + 's\n';

  if (j.summary) text += '\nZUSAMMENFASSUNG:\n' + String(j.summary).substring(0, 500) + '\n';
  if (j.notes && j.notes !== j.summary) text += '\nNOTIZEN: ' + String(j.notes).substring(0, 300) + '\n';
  if (j.recording_url) text += '\nAUFNAHME ANHOEREN:\n' + j.recording_url + '\n';
  if (j.transcript) text += '\nTRANSKRIPT (Auszug):\n' + String(j.transcript).substring(0, 800);

  out.push({ json: { tg_text: text.substring(0, 3900) } });
}
return out;
